     1→/**
     2→ * 마크다운 파서 - 외부 라이브러리 없이 구현
     3→ * 지원: 제목, 굵게/기울임, 인라인 코드, 코드 블록, 링크, 이미지,
     4→ *       순서/비순서 목록(중첩), 인용구(중첩), 수평선, 단락, 줄바꿈, 이스케이프
     5→ */
     6→
     7→const MarkdownParser = (() => {
     8→  // 이스케이프 가능한 특수문자 목록
     9→  const ESCAPABLE = /\\([\\`*_{}\[\]()#+\-.!|])/g;
    10→
    11→  // HTML 특수문자를 엔티티로 변환 (XSS 방지)
    12→  function escapeHtml(text) {
    13→    return text
    14→      .replace(/&/g, '&amp;')
    15→      .replace(/</g, '&lt;')
    16→      .replace(/>/g, '&gt;')
    17→      .replace(/"/g, '&quot;');
    18→  }
    19→
    20→  // 이스케이프 문자를 플레이스홀더로 치환 (파싱 중 보호)
    21→  const escapeMap = new Map();
    22→  let escapeCounter = 0;
    23→
    24→  function protectEscapes(text) {
    25→    escapeCounter = 0;
    26→    escapeMap.clear();
    27→    return text.replace(ESCAPABLE, (_, ch) => {
    28→      const key = `\x00ESC${escapeCounter++}\x00`;
    29→      escapeMap.set(key, escapeHtml(ch));
    30→      return key;
    31→    });
    32→  }
    33→
    34→  function restoreEscapes(text) {
    35→    for (const [key, val] of escapeMap) {
    36→      text = text.split(key).join(val);
    37→    }
    38→    return text;
    39→  }
    40→
    41→  // 인라인 요소 파싱 (굵게, 기울임, 인라인 코드, 링크, 이미지)
    42→  function parseInline(text) {
    43→    // 인라인 코드 블록 (백틱)을 먼저 보호
    44→    const codeMap = new Map();
    45→    let codeIdx = 0;
    46→    text = text.replace(/(`+)([\s\S]*?)\1/g, (_, ticks, content) => {
    47→      const key = `\x00CODE${codeIdx++}\x00`;
    48→      codeMap.set(key, `<code>${escapeHtml(content)}</code>`);
    49→      return key;
    50→    });
    51→
    52→    // 원시 HTML 이스케이프 (XSS 방지) — 인라인 코드 보호 후, 마크다운 패턴 처리 전
    53→    text = text.replace(/&(?!(?:[a-zA-Z]+|#\d+|#x[0-9a-fA-F]+);)/g, '&amp;');
    54→    text = text.replace(/</g, '&lt;').replace(/>/g, '&gt;');
    55→
    56→    // 이미지 ![alt](url "title")
    57→    text = text.replace(/!\[([^\]]*)\]\(([^)"]*?)(?:\s+"([^"]*)")?\)/g, (_, alt, src, title) => {
    58→      const titleAttr = title ? ` title="${escapeHtml(title)}"` : '';
    59→      return `<img src="${escapeHtml(src)}" alt="${escapeHtml(alt)}"${titleAttr}>`;
    60→    });
    61→
    62→    // 링크 [text](url "title")
    63→    text = text.replace(/\[([^\]]*)\]\(([^)"]*?)(?:\s+"([^"]*)")?\)/g, (_, linkText, href, title) => {
    64→      const titleAttr = title ? ` title="${escapeHtml(title)}"` : '';
    65→      return `<a href="${escapeHtml(href)}"${titleAttr} target="_blank" rel="noopener">${parseInlineBasic(linkText)}</a>`;
    66→    });
    67→
    68→    // 굵게+기울임 ***text*** 또는 ___text___
    69→    text = text.replace(/(\*{3}|_{3})(?!\s)([\s\S]*?)(?<!\s)\1/g, (_, __, content) => {
    70→      return `<strong><em>${parseInlineBasic(content)}</em></strong>`;
    71→    });
    72→
    73→    // 굵게 **text** 또는 __text__
    74→    text = text.replace(/(\*{2}|_{2})(?!\s)([\s\S]*?)(?<!\s)\1/g, (_, __, content) => {
    75→      return `<strong>${parseInlineBasic(content)}</strong>`;
    76→    });
    77→
    78→    // 기울임 *text* 또는 _text_
    79→    text = text.replace(/(\*|_)(?!\s)([\s\S]*?)(?<!\s)\1/g, (_, __, content) => {
    80→      return `<em>${parseInlineBasic(content)}</em>`;
    81→    });
    82→
    83→    // 취소선 ~~text~~
    84→    text = text.replace(/~~([\s\S]*?)~~/g, (_, content) => {
    85→      return `<del>${content}</del>`;
    86→    });
    87→
    88→    // 줄바꿈: 줄 끝 공백 2개 또는 \
    89→    text = text.replace(/  \n/g, '<br>\n');
    90→    text = text.replace(/\\\n/g, '<br>\n');
    91→    // 나머지 줄바꿈은 공백으로 (단락 내 연속 줄)
    92→    text = text.replace(/\n/g, ' ');
    93→
    94→    // 인라인 코드 복원
    95→    for (const [key, val] of codeMap) {
    96→      text = text.split(key).join(val);
    97→    }
    98→
    99→    return text;
   100→  }
   101→
   102→  // 재귀 없는 간단한 인라인 파싱 (링크 내부 텍스트 등에 사용)
   103→  function parseInlineBasic(text) {
   104→    text = text.replace(/(\*{3}|_{3})(?!\s)([\s\S]*?)(?<!\s)\1/g, (_, __, c) => `<strong><em>${c}</em></strong>`);
   105→    text = text.replace(/(\*{2}|_{2})(?!\s)([\s\S]*?)(?<!\s)\1/g, (_, __, c) => `<strong>${c}</strong>`);
   106→    text = text.replace(/(\*|_)(?!\s)([\s\S]*?)(?<!\s)\1/g, (_, __, c) => `<em>${c}</em>`);
   107→    return text;
   108→  }
   109→
   110→  // 코드 블록 파싱 (펜스 코드 블록 ```lang ... ```)
   111→  function parseCodeBlocks(text) {
   112→    return text.replace(/^(`{3,}|~{3,})([^\n]*)\n([\s\S]*?)^\1\s*$/gm, (_, fence, lang, code) => {
   113→      const langClass = lang.trim() ? ` class="language-${escapeHtml(lang.trim())}"` : '';
   114→      const langLabel = lang.trim() ? `<span class="code-lang">${escapeHtml(lang.trim())}</span>` : '';
   115→      return `<div class="code-block-wrapper">${langLabel}<pre><code${langClass}>${escapeHtml(code)}</code></pre></div>`;
   116→    });
   117→  }
   118→
   119→  // 목록 파싱 (순서/비순서, 중첩 지원)
   120→  function parseLists(lines) {
   121→    const result = [];
   122→    let i = 0;
   123→
   124→    while (i < lines.length) {
   125→      const line = lines[i];
   126→
   127→      // 비순서 목록 항목 감지
   128→      const ulMatch = line.match(/^(\s*)[-*+]\s+(.*)/);
   129→      // 순서 목록 항목 감지
   130→      const olMatch = line.match(/^(\s*)\d+\.\s+(.*)/);
   131→
   132→      if (ulMatch || olMatch) {
   133→        const isOrdered = !!olMatch;
   134→        const match = ulMatch || olMatch;
   135→        const baseIndent = match[1].length;
   136→
   137→        const items = [];
   138→        while (i < lines.length) {
   139→          const l = lines[i];
   140→          const ulM = l.match(/^(\s*)[-*+]\s+(.*)/);
   141→          const olM = l.match(/^(\s*)\d+\.\s+(.*)/);
   142→          const m = ulM || olM;
   143→
   144→          if (!m) break;
   145→
   146→          const indent = m[1].length;
   147→          if (indent < baseIndent) break;
   148→
   149→          if (indent === baseIndent) {
   150→            items.push({ indent, content: m[2], children: [] });
   151→            i++;
   152→          } else {
   153→            // 중첩 항목: 이전 아이템의 children에 추가
   154→            if (items.length > 0) {
   155→              items[items.length - 1].children.push(l);
   156→            }
   157→            i++;
   158→          }
   159→        }
   160→
   161→        const tag = isOrdered ? 'ol' : 'ul';
   162→        const html = renderList(items, tag);
   163→        result.push(html);
   164→      } else {
   165→        result.push(line);
   166→        i++;
   167→      }
   168→    }
   169→
   170→    return result;
   171→  }
   172→
   173→  function renderList(items, tag) {
   174→    const listItems = items.map(item => {
   175→      let content = parseInline(item.content);
   176→      if (item.children.length > 0) {
   177→        const childLines = item.children;
   178→        const childResult = parseLists(childLines);
   179→        // 중첩 목록 판단
   180→        const firstChild = childLines[0] || '';
   181→        const isChildOrdered = /^\s*\d+\.\s/.test(firstChild);
   182→        content += '\n' + childResult.join('\n');
   183→      }
   184→      return `<li>${content}</li>`;
   185→    });
   186→    return `<${tag}>\n${listItems.join('\n')}\n</${tag}>`;
   187→  }
   188→
   189→  // 인용구 파싱 (중첩 지원)
   190→  function parseBlockquotes(text) {
   191→    // 단계별로 중첩 처리
   192→    let prev = '';
   193→    while (prev !== text) {
   194→      prev = text;
   195→      text = text.replace(/^((?:[ \t]*>[ \t]?.*\n?)+)/gm, (match) => {
   196→        // > 를 하나씩 벗기기
   197→        const inner = match.replace(/^[ \t]*>[ \t]?/gm, '');
   198→        const processed = parseBlockquotes(inner);
   199→        // 인라인 서식 적용 (이미 HTML 태그로 시작하는 줄은 건너뜀)
   200→        const withInline = processed.replace(/^(?!<\w)(.+)$/gm, (line) => parseInline(line));
   201→        return `<blockquote>\n${withInline}</blockquote>\n`;
   202→      });
   203→    }
   204→    return text;
   205→  }
   206→
   207→  // 수평선 파싱
   208→  function parseHorizontalRules(text) {
   209→    return text.replace(/^[ \t]*([-*_])([ \t]*\1){2,}[ \t]*$/gm, '<hr>');
   210→  }
   211→
   212→  // 제목 파싱 (ATX 스타일)
   213→  function parseHeadings(text) {
   214→    return text.replace(/^(#{1,6})\s+(.+?)(?:\s+#+\s*)?$/gm, (_, hashes, content) => {
   215→      const level = hashes.length;
   216→      const id = content.toLowerCase().replace(/[^\w\s-]/g, '').replace(/\s+/g, '-');
   217→      return `<h${level} id="${id}">${parseInline(content)}</h${level}>`;
   218→    });
   219→  }
   220→
   221→  // 단락 파싱 (빈 줄로 구분)
   222→  function parseParagraphs(blocks) {
   223→    return blocks.map(block => {
   224→      // 이미 블록 레벨 HTML 태그로 시작하면 그대로 반환
   225→      if (/^<(h[1-6]|ul|ol|li|blockquote|pre|hr|div)[\s>]/.test(block.trim())) {
   226→        return block;
   227→      }
   228→      if (block.trim() === '') return '';
   229→      return `<p>${parseInline(block.trim())}</p>`;
   230→    }).filter(b => b !== '');
   231→  }
   232→
   233→  // 메인 파싱 함수
   234→  function parse(markdown) {
   235→    if (!markdown) return '';
   236→
   237→    // 이스케이프 문자 보호
   238→    let text = protectEscapes(markdown);
   239→
   240→    // 줄 끝 정규화
   241→    text = text.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
   242→
   243→    // 1단계: 코드 블록 추출 및 보호 (파싱 중 내용 변환 방지)
   244→    const codeBlockMap = new Map();
   245→    let cbIdx = 0;
   246→    text = text.replace(/^(`{3,}|~{3,})([^\n]*)\n([\s\S]*?)^\1[ \t]*$/gm, (match, fence, lang, code) => {
   247→      const key = `\x00CB${cbIdx++}\x00`;
   248→      const langClass = lang.trim() ? ` class="language-${escapeHtml(lang.trim())}"` : '';
   249→      const langLabel = lang.trim() ? `<span class="code-lang">${escapeHtml(lang.trim())}</span>` : '';
   250→      codeBlockMap.set(key, `<div class="code-block-wrapper">${langLabel}<pre><code${langClass}>${escapeHtml(code)}</code></pre></div>`);
   251→      return key;
   252→    });
   253→
   254→    // 2단계: 수평선 파싱
   255→    text = parseHorizontalRules(text);
   256→
   257→    // 3단계: 제목 파싱
   258→    text = parseHeadings(text);
   259→
   260→    // 4단계: 인용구 파싱
   261→    text = parseBlockquotes(text);
   262→
   263→    // 5단계: 목록 파싱 (줄 단위)
   264→    const lines = text.split('\n');
   265→    const processedLines = parseLists(lines);
   266→    text = processedLines.join('\n');
   267→
   268→    // 6단계: 코드 블록 복원
   269→    for (const [key, val] of codeBlockMap) {
   270→      text = text.split(key).join(val);
   271→    }
   272→
   273→    // 7단계: 빈 줄 기준으로 블록 분리 후 단락 처리
   274→    const blocks = text.split(/\n{2,}/);
   275→    const parsed = parseParagraphs(blocks);
   276→    text = parsed.join('\n\n');
   277→
   278→    // 8단계: 이스케이프 복원
   279→    text = restoreEscapes(text);
   280→
   281→    return text;
   282→  }
   283→
   284→  return { parse };
   285→})();
