     1→/**
     2→ * 에디터 로직
     3→ * - 실시간 미리보기 업데이트
     4→ * - 툴바 버튼 액션 (커서 위치에 마크다운 삽입, 선택 텍스트 감싸기)
     5→ * - 드래그로 패널 크기 조절
     6→ * - 키보드 단축키 (Ctrl+B, Ctrl+I, Ctrl+K)
     7→ * - localStorage 자동 저장/복원
     8→ * - HTML 내보내기
     9→ */
    10→
    11→(function () {
    12→  'use strict';
    13→
    14→  // ── DOM 참조 ───────────────────────────────────────────────
    15→  const editor   = document.getElementById('editor');
    16→  const preview  = document.getElementById('preview');
    17→  const resizer  = document.getElementById('resizer');
    18→  const editorPane = document.querySelector('.editor-pane');
    19→  const editorArea = document.querySelector('.editor-area');
    20→  const wordCount  = document.getElementById('word-count');
    21→  const lineCount  = document.getElementById('line-count');
    22→  const saveStatus = document.getElementById('save-status');
    23→  const saveDot    = document.getElementById('save-dot');
    24→
    25→  // ── 상수 ───────────────────────────────────────────────────
    26→  const STORAGE_KEY   = 'md-editor-content';
    27→  const SAVE_DELAY_MS = 800;   // 자동 저장 딜레이
    28→  const DEFAULT_CONTENT = `# 마크다운 에디터에 오신 것을 환영합니다
    29→
    30→## 기본 텍스트 서식
    31→
    32→**굵게**, *기울임*, ***굵게+기울임***, ~~취소선~~
    33→
    34→## 코드
    35→
    36→인라인 \`코드\` 예시
    37→
    38→\`\`\`javascript
    39→// 코드 블록 예시
    40→function greet(name) {
    41→  return \`안녕하세요, \${name}!\`;
    42→}
    43→console.log(greet('세계'));
    44→\`\`\`
    45→
    46→## 링크 & 이미지
    47→
    48→[GitHub](https://github.com "GitHub")
    49→
    50→## 목록
    51→
    52→- 항목 1
    53→  - 중첩 항목 1-1
    54→  - 중첩 항목 1-2
    55→- 항목 2
    56→- 항목 3
    57→
    58→1. 첫 번째
    59→2. 두 번째
    60→3. 세 번째
    61→
    62→## 인용구
    63→
    64→> 인용구 예시입니다.
    65→>
    66→> > 중첩 인용구도 지원합니다.
    67→
    68→## 수평선
    69→
    70→---
    71→
    72→## 단축키
    73→
    74→| 단축키 | 기능 |
    75→| --- | --- |
    76→| Ctrl+B | 굵게 |
    77→| Ctrl+I | 기울임 |
    78→| Ctrl+K | 링크 삽입 |
    79→`;
    80→
    81→  // ── 초기화 ─────────────────────────────────────────────────
    82→  function init() {
    83→    loadContent();
    84→    updatePreview();
    85→    updateStatus();
    86→    bindToolbar();
    87→    bindKeyboardShortcuts();
    88→    bindResizer();
    89→    bindEditorEvents();
    90→  }
    91→
    92→  // ── 콘텐츠 로드/저장 ───────────────────────────────────────
    93→  function loadContent() {
    94→    try {
    95→      const saved = localStorage.getItem(STORAGE_KEY);
    96→      editor.value = saved !== null ? saved : DEFAULT_CONTENT;
    97→    } catch {
    98→      editor.value = DEFAULT_CONTENT;
    99→    }
   100→  }
   101→
   102→  let saveTimer = null;
   103→
   104→  function scheduleAutosave() {
   105→    clearTimeout(saveTimer);
   106→    setSaveStatus('저장 중...', false);
   107→    saveTimer = setTimeout(() => {
   108→      try {
   109→        localStorage.setItem(STORAGE_KEY, editor.value);
   110→        setSaveStatus('저장됨', true);
   111→      } catch {
   112→        setSaveStatus('저장 실패', false);
   113→      }
   114→    }, SAVE_DELAY_MS);
   115→  }
   116→
   117→  function setSaveStatus(text, saved) {
   118→    if (saveStatus) saveStatus.textContent = text;
   119→    if (saveDot) saveDot.className = 'statusbar-dot' + (saved ? ' saved' : '');
   120→  }
   121→
   122→  // ── 미리보기 업데이트 ──────────────────────────────────────
   123→  function updatePreview() {
   124→    const html = MarkdownParser.parse(editor.value);
   125→    preview.innerHTML = html;
   126→  }
   127→
   128→  // ── 상태바 업데이트 ────────────────────────────────────────
   129→  function updateStatus() {
   130→    const text   = editor.value;
   131→    const words  = text.trim() === '' ? 0 : text.trim().split(/\s+/).length;
   132→    const lines  = text === '' ? 1 : text.split('\n').length;
   133→    if (wordCount) wordCount.textContent = `${words} 단어`;
   134→    if (lineCount) lineCount.textContent = `${lines} 줄`;
   135→  }
   136→
   137→  // ── 에디터 이벤트 바인딩 ───────────────────────────────────
   138→  function bindEditorEvents() {
   139→    editor.addEventListener('input', () => {
   140→      updatePreview();
   141→      updateStatus();
   142→      scheduleAutosave();
   143→    });
   144→
   145→    // Tab 키 들여쓰기 처리
   146→    editor.addEventListener('keydown', (e) => {
   147→      if (e.key === 'Tab') {
   148→        e.preventDefault();
   149→        insertAtCursor('  ');
   150→      }
   151→    });
   152→  }
   153→
   154→  // ── 커서 위치에 텍스트 삽입 ────────────────────────────────
   155→  function insertAtCursor(text) {
   156→    const start = editor.selectionStart;
   157→    const end   = editor.selectionEnd;
   158→    const val   = editor.value;
   159→    editor.value = val.slice(0, start) + text + val.slice(end);
   160→    editor.selectionStart = editor.selectionEnd = start + text.length;
   161→    editor.focus();
   162→    editor.dispatchEvent(new Event('input'));
   163→  }
   164→
   165→  // ── 선택 영역 감싸기 또는 앞에 삽입 ──────────────────────
   166→  /**
   167→   * @param {string} prefix  - 선택 영역 앞에 삽입할 텍스트
   168→   * @param {string} suffix  - 선택 영역 뒤에 삽입할 텍스트 (없으면 prefix와 동일)
   169→   * @param {string} placeholder - 선택 없을 때 사용할 기본 텍스트
   170→   */
   171→  function wrapSelection(prefix, suffix, placeholder) {
   172→    if (suffix === undefined) suffix = prefix;
   173→    const start = editor.selectionStart;
   174→    const end   = editor.selectionEnd;
   175→    const val   = editor.value;
   176→    const selected = val.slice(start, end) || placeholder || '';
   177→    const wrapped  = prefix + selected + suffix;
   178→    editor.value = val.slice(0, start) + wrapped + val.slice(end);
   179→
   180→    // 커서를 삽입된 내용 안으로 이동
   181→    const newStart = start + prefix.length;
   182→    const newEnd   = newStart + selected.length;
   183→    editor.selectionStart = newStart;
   184→    editor.selectionEnd   = newEnd;
   185→    editor.focus();
   186→    editor.dispatchEvent(new Event('input'));
   187→  }
