   189→  // ── 줄 앞에 접두사 삽입 ────────────────────────────────────
   190→  function insertLinePrefix(prefix) {
   191→    const start = editor.selectionStart;
   192→    const val   = editor.value;
   193→    // 현재 줄의 시작 위치 계산
   194→    const lineStart = val.lastIndexOf('\n', start - 1) + 1;
   195→    editor.value = val.slice(0, lineStart) + prefix + val.slice(lineStart);
   196→    editor.selectionStart = editor.selectionEnd = start + prefix.length;
   197→    editor.focus();
   198→    editor.dispatchEvent(new Event('input'));
   199→  }
