   243→  function insertCodeBlock() {
   244→    const start    = editor.selectionStart;
   245→    const end      = editor.selectionEnd;
   246→    const selected = editor.value.slice(start, end);
   247→    const val      = editor.value;
   248→
   249→    if (selected.includes('\n')) {
