   251→      const block = '```\n' + selected + '\n```';
   252→      editor.value = val.slice(0, start) + block + val.slice(end);
   253→      editor.selectionStart = start + 4;
   254→      editor.selectionEnd   = start + 4 + selected.length;
   255→    } else if (selected) {
   256→      // 단일 줄 선택 → 인라인 코드
   257→      wrapSelection('`', '`', selected);
   258→      return;
   259→    } else {
   260→      // 선택 없음 → 코드 블록 삽입
   261→      const block = '```\n코드를 입력하세요\n```';
   262→      editor.value = val.slice(0, start) + block + val.slice(end);
   263→      editor.selectionStart = start + 4;
   264→      editor.selectionEnd   = start + 4 + 11;
   265→    }
   266→    editor.focus();
   267→    editor.dispatchEvent(new Event('input'));
