   276→    if (selected) {
   277→      const lines = selected.split('\n');
   278→      const numbered = lines.map((l, i) => `${i + 1}. ${l}`).join('\n');
   279→      editor.value = val.slice(0, start) + numbered + val.slice(end);
   280→      editor.selectionStart = start;
   281→      editor.selectionEnd   = start + numbered.length;
   282→    } else {
   283→      insertLinePrefix('1. ');
   284→      return;
   285→    }
   286→    editor.focus();
   287→    editor.dispatchEvent(new Event('input'));
   288→  }
