   328→    let startWidth = 0;
   329→
   330→    resizer.addEventListener('mousedown', (e) => {
   331→      isResizing = true;
   332→      startX     = e.clientX;
   333→      startWidth = editorPane.offsetWidth;
   334→      resizer.classList.add('dragging');
   335→      editorArea.classList.add('resizing');
   336→      e.preventDefault();
