   338→
   339→    document.addEventListener('mousemove', (e) => {
   340→      if (!isResizing) return;
   341→      const delta     = e.clientX - startX;
   342→      const totalWidth = editorArea.offsetWidth;
   343→      const newWidth   = Math.max(160, Math.min(totalWidth - 164, startWidth + delta));
   344→      editorPane.style.width = newWidth + 'px';
   345→    });
   346→
   347→    document.addEventListener('mouseup', () => {
   348→      if (!isResizing) return;
   349→      isResizing = false;
   350→      resizer.classList.remove('dragging');
   351→      editorArea.classList.remove('resizing');
   352→    });
   353→
   354→    // 터치 지원
   355→    resizer.addEventListener('touchstart', (e) => {
   356→      isResizing = true;
   357→      startX     = e.touches[0].clientX;
   358→      startWidth = editorPane.offsetWidth;
   359→      resizer.classList.add('dragging');
   360→      e.preventDefault();
   361→    }, { passive: false });
   362→
   363→    document.addEventListener('touchmove', (e) => {
   364→      if (!isResizing) return;
   365→      const delta     = e.touches[0].clientX - startX;
   366→      const totalWidth = editorArea.offsetWidth;
   367→      const newWidth   = Math.max(160, Math.min(totalWidth - 164, startWidth + delta));
   368→      editorPane.style.width = newWidth + 'px';
   369→    }, { passive: true });
   370→
   371→    document.addEventListener('touchend', () => {
   372→      if (!isResizing) return;
   373→      isResizing = false;
   374→      resizer.classList.remove('dragging');
   375→      editorArea.classList.remove('resizing');
   376→    });
   377→  }
